const c = $json;

// last seen por canal
const iosSeen = Number(c.ios_last_seen_at || 0);
const androidSeen = Number(c.android_last_seen_at || 0);

// web: só considera se tiver browser e last_seen_at
const webSeen = c.browser ? Number(c.last_seen_at || 0) : 0;

const maxSeen = Math.max(iosSeen, androidSeen, webSeen);

let platform = 'unknown';
let operationalSystem = null;
let osVersion = null;
let appVersion = null;
let deviceModel = null;
let browserName = null;

if (maxSeen === iosSeen && iosSeen > 0) {
  platform = 'ios';
  operationalSystem = 'iOS';
  osVersion = c.ios_os_version || null;
  appVersion = c.ios_app_version || null;
  deviceModel = c.ios_device || null;

} else if (maxSeen === androidSeen && androidSeen > 0) {
  platform = 'android';
  operationalSystem = 'Android';
  osVersion = c.android_os_version || null;
  appVersion = c.android_app_version || null;
  deviceModel = c.android_device || null;

} else if (maxSeen === webSeen && webSeen > 0) {
  platform = 'Web';
  // Web: OS real + browser version
  operationalSystem = c.os || null;            // ex: Windows 10
  osVersion = c.browser_version || null;       // ex: 144.0.0
  browserName = c.browser || null;             // ex: Chrome / Edge
  appVersion = null;
  deviceModel = null;
}

return [{
  json: {
    ...c,
    platform,
    operationalSystem,
    osVersion,
    appVersion,
    deviceModel,
    browserName,
  }
}];

const topic = $json.body?.topic || 'unknown';
const item = $json.body?.data?.item || {};
const ticketId = item.ticket?.ticket_id || item.ticket_id || '';

// Anti auto-trigger: ignora ticket.attribute.updated quando o atributo é Azure ID ou Azure link
// (disparado pelo próprio workflow ao atualizar o ticket no Intercom após criar Issue)
if (topic === 'ticket.attribute.updated') {
  const attr = item.ticket_part?.updated_attribute_data?.attribute?.label || '';
  if (attr === 'Azure ID' || attr === 'Azure link') {
    $execution.customData.set('topic', topic + ' (ignored: ' + attr + ')');
    $execution.customData.set('ticket_id', ticketId);
    return [];
  }
}

$execution.customData.set('topic', topic);
$execution.customData.set('ticket_id', ticketId);
return [{ json: $json }];

// Pega o ticket_type de forma "à prova de variação" com validação segura
const item = $input.first()?.json?.body?.data?.item ?? {};
const type = item?.ticket_type?.name ?? null;

const tagMap = {
  "Assinaturas/Pagamentos": "Ongoing payments",
  "Catálogo": "Ongoing catálogo",
  "Estatística": "Ongoing estatística",
  "Estoque": "Ongoing estoque",
  "Fiado": "Ongoing fiado",
  "Finanças": "Ongoing finanças",
  "Variantes": "Ongoing variantes",
  "Problemas gerais": "Ongoing geral"
};

// Normaliza a entrada removendo espaços extras
const normalizedType = type?.trim?.();

// Busca no mapa com fallback explícito
const azureTag = normalizedType && tagMap.hasOwnProperty(normalizedType) 
  ? tagMap[normalizedType] 
  : null;

return [
  {
    json: {
      azureTag,
    },
  },
];

const map = {
  "4572477": "To Do",
  "4572478": "Doing",
  "4572479": "CS",
  "4572485": "Ready",
  "4572490": "On Hold",
  "4572484": "Done",
  "4645359": "Redoing",
  "4645360": "CS Return"
};

const newAzureState = map[String($json.ticket_state)];

if (!newAzureState) {
  throw new Error("ticket_state não mapeado: " + $json.ticket_state);
}

return [{ ...$json, newAzureState }];

const anexos = $node["Webhook Intercom (ticket created)"].json.body?.data?.item?.ticket_attributes?.Anexos ?? [];
const azureId = items[0].json["Azure ID"];

return anexos.map(a => ({ json: { ...items[0].json, azureId, fileName: a.name, fileUrl: a.url, } }));

// pega o azureId do primeiro item (todos têm o mesmo)
const azureId = items[0].json.azureId || items[0].json.azureid || null;

const ops = items.map(i => {
  const url = i.json.url;

  return {
    op: "add",
    path: "/relations/-",
    value: {
      rel: "AttachedFile",
      url,
      attributes: {
        comment: "Anexo do Intercom"
      }
    }
  };
});

return [
  {
    json: {
      azureId,
      ops
    }
  }
];

