const azureId = $json.azureId;
const text = $json.commentText || "";
const html = $json.commentHtml || "";
const authorName = $json.authorName || "Intercom";

// Anti-loop: ignora comentários que vieram do Azure
if (html.includes('<b>[') && html.includes(']</b>')) {
  return [];
}

// Validação: Azure ID é obrigatório para sincronizar comentários
if (!azureId || azureId === 0) {
  throw new Error("Azure ID não encontrado no ticket. O ticket precisa ter um Azure ID vinculado para sincronizar comentários.");
}

// 1) Prioriza imagens do HTML do ticket_part (comentário específico)
let imageUrls = [...html.matchAll(/<img[^>]+src="([^"]+)"/g)]
  .map(m => m[1].replace(/&amp;/g, "&"));

// 2) Fallback: anexos do ticket_part
if (!imageUrls.length) {
  const attachments = $json.attachments || [];
  imageUrls = attachments
    .filter(a => (a.content_type || "").startsWith("image/"))
    .map(a => (a.url || "").replace(/&amp;/g, "&"));
}

return [{ json: { azureId, text, imageUrls, authorName } }];

// Comentário simples sem imagens
const azureId = $json.azureId;
const text = $json.text || "(sem texto)";
const authorName = $json.authorName || 'Intercom';

// Prefixo anti-loop + nome do CSer
return [{
  json: {
    azureId,
    comment: '[Intercom] <b>[' + authorName + ']</b><br>' + text
  }
}];

const azureId = items[0].json.azureId;
const text = items[0].json.text || "Atualização com imagem";
const authorName = items[0].json.authorName || 'Intercom';

// Agrega todas as imagens uploadadas ao Azure
const imageHtml = items.map(item => {
  const attachmentUrl = item.json.url;
  return '<br><br><img src="' + attachmentUrl + '" alt="imagem" />';
}).join('');

// Prefixo anti-loop + nome do CSer
return [{
  json: {
    azureId,
    comment: '[Intercom] <b>[' + authorName + ']</b><br>' + text + imageHtml
  }
}];

const urls = $json.imageUrls || [];
const azureId = $json.azureId;
const text = $json.text;
const authorName = $json.authorName || 'Intercom';

return urls.map(url => ({
  json: {
    azureId,
    text,
    authorName,
    imageUrl: url.replace(/&amp;/g, '&').trim()
  }
}));

const ticket = $json.body.data.item.ticket;
const ticketPart = $json.body.data.item.ticket_part;
const azureId = ticket.ticket_attributes?.['Azure ID'];

// Só processa se for atualização de Anexos
const updatedAttr = ticketPart?.updated_attribute_data?.attribute?.label;
if (updatedAttr !== 'Anexos') {
  return [];
}

// Valida Azure ID
if (!azureId) {
  throw new Error('Azure ID não encontrado no ticket. Não é possível sincronizar anexos.');
}

// Descobre quais anexos são novos comparando previous vs current
const currentNames = ticketPart.updated_attribute_data?.value?.label || [];
const previousNames = ticketPart.updated_attribute_data?.value?.previous || [];
const newNames = currentNames.filter(name => !previousNames.includes(name));

if (newNames.length === 0) {
  return [];
}

// Busca URLs dos novos anexos no campo Anexos do ticket
const allAnexos = ticket.ticket_attributes?.Anexos || [];
const newAnexos = allAnexos.filter(a => newNames.includes(a.name));

return newAnexos.map(a => ({
  json: {
    azureId: Number(String(azureId).trim()),
    fileName: a.name,
    fileUrl: a.url,
    contentType: a.content_type
  }
}));

const azureId = items[0].json.azureId;

const ops = items.map(i => ({
  op: 'add',
  path: '/relations/-',
  value: {
    rel: 'AttachedFile',
    url: i.json.url,
    attributes: {
      comment: 'Anexo do Intercom (attribute update)'
    }
  }
}));

return [{ json: { azureId, ops } }];

